template <class T>
class Node {
public:
    T data;
    Node<T>* left;
    Node<T>* right;

    Node(T value) {
        data = value;
        left = nullptr;
        right = nullptr;
    }
};

template <class T>
class BST {
private:
    Node<T>* root;

    Node<T>* Insert(Node<T>* node, T value) {
        if (node == nullptr) {
            return new Node<T>(value);
        }

        if (value < node->data) {
            node->left = Insert(node->left, value);
        } else {
            node->right = Insert(node->right, value);
        }

        return node;
    }

public:
    BST() {
        root = nullptr;
    }

    void Insert(T value) {
        root = Insert(root, value);
    }

    void CreateTree(T arr[], int n) {
        for (int i = 0; i < n; i++) {
            Insert(arr[i]);
        }
    }

    T Max() {
        Node<T>* current = root;
        while (current->right != nullptr) {
            current = current->right;
        }
        return current->data;
    }
};

#include <iostream>
#include <map>
#include <vector>
#include <string>
using namespace std;

struct Influencer {
    int id;
    string name;
    string instagramId;
};

map<string, vector<Influencer>> campaigns;

void create_campaign(const string& clientName, const vector<Influencer>& influencers) {
    campaigns[clientName] = influencers;
}

void print_influencers_data() {
    for (const auto& campaign : campaigns) {
        cout << "Client: " << campaign.first << endl;
        for (const auto& influencer : campaign.second) {
            cout << influencer.id << " - "
                 << influencer.name << " - "
                 << influencer.instagramId << endl;
        }
    }
}

void delete_influencers_from_campaign(const string& clientName, int influencerId) {
    vector<Influencer>& list = campaigns[clientName];

    for (auto it = list.begin(); it != list.end(); ) {
        if (it->id == influencerId) {
            it = list.erase(it);
        } else {
            ++it;
        }
    }
}
